import type { ReactNode } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import {
  Card,
  CardAction,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { cn } from "@/lib/utils";

const sectionCardVariants = cva("shadow-panel", {
  variants: {
    tone: {
      default: "bg-panel-background text-panel-foreground",
      muted: "bg-surface-2 text-panel-foreground",
      transparent: "bg-panel-background/90 text-panel-foreground backdrop-blur-sm",
    },
  },
  defaultVariants: {
    tone: "default",
  },
});

type SectionCardProps = VariantProps<typeof sectionCardVariants> & {
  title?: string;
  description?: string;
  action?: ReactNode;
  children: ReactNode;
  className?: string;
  contentClassName?: string;
};

export function SectionCard({
  title,
  description,
  action,
  children,
  className,
  contentClassName,
  tone,
}: SectionCardProps) {
  return (
    <Card
      className={cn(
        "border border-border/70 bg-panel-background/95 shadow-panel",
        sectionCardVariants({ tone }),
        className,
      )}
    >
      {title || description || action ? (
        <CardHeader className="border-b border-border/60 pb-4">
          <div className="space-y-1">
            {title ? <CardTitle>{title}</CardTitle> : null}
            {description ? <CardDescription>{description}</CardDescription> : null}
          </div>
          {action ? <CardAction>{action}</CardAction> : null}
        </CardHeader>
      ) : null}
      <CardContent className={cn("pt-5", contentClassName)}>{children}</CardContent>
    </Card>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import type { NavItem } from "@/lib/navigation";
import {
  SidebarMenuBadge,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar";
import { cn } from "@/lib/utils";

type SidebarNavItemProps = {
  item: NavItem;
};

export function SidebarNavItem({ item }: SidebarNavItemProps) {
  const pathname = usePathname();
  const isActive = item.href ? pathname === item.href : false;
  const Icon = item.icon;

  return (
    <SidebarMenuItem>
      <SidebarMenuButton
        asChild={!item.disabled && Boolean(item.href)}
        isActive={isActive}
        tooltip={item.title}
        className={cn(
          "h-11 rounded-2xl px-3 text-[0.95rem] font-medium text-sidebar-foreground/80 transition-all duration-150 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground data-active:bg-sidebar-active-background data-active:text-sidebar-active-foreground data-active:shadow-soft",
          item.disabled && "cursor-not-allowed opacity-45 hover:bg-transparent",
        )}
      >
        {!item.disabled && item.href ? (
          <Link href={item.href}>
            <Icon className="size-[18px]" />
            <span>{item.title}</span>
          </Link>
        ) : (
          <>
            <Icon className="size-[18px]" />
            <span>{item.title}</span>
          </>
        )}
      </SidebarMenuButton>
      {item.badge ? (
        <SidebarMenuBadge className="right-3 rounded-full border border-border/60 bg-surface-2 px-1.5 text-[0.62rem] font-semibold text-muted-foreground">
          {item.badge}
        </SidebarMenuBadge>
      ) : null}
    </SidebarMenuItem>
  );
}

import type { LucideIcon } from "lucide-react";
import { ArrowDownRight, ArrowRight, ArrowUpRight } from "lucide-react";
import { AppCard } from "@/components/admin/app-card";
import { cn } from "@/lib/utils";

type StatCardProps = {
  label: string;
  value: string;
  delta: string;
  trend: "up" | "down" | "stable";
  description: string;
  icon: LucideIcon;
};

const trendStyles = {
  up: "text-success",
  down: "text-destructive",
  stable: "text-muted-foreground",
};

const trendIcons = {
  up: ArrowUpRight,
  down: ArrowDownRight,
  stable: ArrowRight,
};

export function StatCard({
  label,
  value,
  delta,
  trend,
  description,
  icon: Icon,
}: StatCardProps) {
  const TrendIcon = trendIcons[trend];

  return (
    <AppCard className="gap-4 bg-linear-to-br from-panel-background via-panel-background to-surface-3/80">
      <div className="flex items-start justify-between gap-4">
        <div className="space-y-2">
          <p className="text-sm font-medium text-muted-foreground">{label}</p>
          <div className="flex items-end gap-3">
            <p className="text-3xl font-semibold tracking-[-0.05em] text-foreground">
              {value}
            </p>
            <span
              className={cn(
                "inline-flex items-center gap-1 rounded-full border border-current/12 px-2 py-1 text-xs font-semibold",
                trendStyles[trend],
              )}
            >
              <TrendIcon className="size-3.5" />
              {delta}
            </span>
          </div>
        </div>
        <div className="rounded-2xl border border-primary/20 bg-primary/12 p-3 text-primary shadow-soft">
          <Icon className="size-5" />
        </div>
      </div>
      <p className="text-sm leading-6 text-muted-foreground">{description}</p>
    </AppCard>
  );
}

import type { ReactNode } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

const statusBadgeVariants = cva(
  "rounded-full border px-2.5 py-1 text-[0.68rem] font-semibold uppercase tracking-[0.16em]",
  {
    variants: {
      status: {
        scheduled:
          "border-info/25 bg-info/10 text-info dark:border-info/30 dark:bg-info/15",
        "en-route":
          "border-primary/30 bg-primary/15 text-primary dark:border-primary/35 dark:bg-primary/18",
        boarding:
          "border-warning/25 bg-warning/12 text-warning dark:border-warning/30 dark:bg-warning/18",
        completed:
          "border-success/25 bg-success/12 text-success dark:border-success/30 dark:bg-success/18",
        delayed:
          "border-warning/25 bg-warning/14 text-warning dark:border-warning/35 dark:bg-warning/20",
        cancelled:
          "border-destructive/20 bg-destructive/12 text-destructive dark:border-destructive/30 dark:bg-destructive/18",
        available:
          "border-success/25 bg-success/12 text-success dark:border-success/30 dark:bg-success/18",
        break:
          "border-warning/25 bg-warning/12 text-warning dark:border-warning/30 dark:bg-warning/18",
        offline:
          "border-border bg-muted/70 text-muted-foreground dark:bg-muted/80",
      },
    },
    defaultVariants: {
      status: "scheduled",
    },
  },
);

type StatusBadgeProps = VariantProps<typeof statusBadgeVariants> & {
  className?: string;
  children: ReactNode;
};

export function StatusBadge({
  status,
  children,
  className,
}: StatusBadgeProps) {
  return (
    <Badge
      variant="outline"
      className={cn(statusBadgeVariants({ status }), className)}
    >
      {children}
    </Badge>
  );
}

